scwin.ds_eq420_onrowpositionchange = function (info) {
    $c.gus.cfPrepareHidVal(ds_eq420, info.rowIndex, ["partCd", "partNm", "unitNm", "inUpr", "stsCd", "useupYn", "eqModelNm", "inAcctNm"]);
